#include<bits/stdc++.h>
using namespace std;
int n,m,k;
int dx[8]={-1,0 ,0,1,-1,-1,1 ,1};
int dy[8]={0 ,-1,1,0,-1,1 ,-1,1};
int id(int x,int y)
{
    return(x-1)*m+y;
}
struct node
{
    int x,y,t,h;
};
bool a[6000010],vis[6000010];
int main()
{
    scanf("%d%d%d",&n,&m,&k);
    int sx,sy,tx,ty;
    scanf("%d%d%d%d",&sx,&sy,&tx,&ty);
    for(int i=1;i<=n;i++)
    {
        string s;
        cin>>s;
        for(int j=1;j<=m;j++)
        {
            a[id(i,j)]=(s[j-1]=='#');
        }
    }
    deque<node> q;
    q.push_back((node){sx,sy,0,0});
    while(1)
    {
        node t=q.front();
        q.pop_front();
        if(vis[id(t.x,t.y)])
        {
            continue;
        }
        vis[id(t.x,t.y)]=true;
        if(t.x==tx&&t.y==ty)
        {
            printf("%d",t.t);
            return 0;
        }
        if(t.h!=0)
        {
            for(int i=0;i<8;i++)
            {
                node t1=(node){t.x+dx[i],t.y+dy[i],t.t,t.h-1};
                if(t1.x<1||t1.x>n||t1.y<1||t1.y>m||vis[id(t1.x,t1.y)])
                {
                    continue;
                }
                q.push_back(t1);
            }
        }
        else
        {
            for(int i=0;i<4;i++)
            {
                node t1=(node){t.x+dx[i],t.y+dy[i],t.t,0};
                if(t1.x<1||t1.x>n||t1.y<1||t1.y>m||vis[id(t1.x,t1.y)])
                {
                    continue;
                }
                if(a[id(t1.x,t1.y)])
                {
                    t1.t++;
                    t1.h=k-1;
                    q.push_back(t1);
                }
                else
                {
                    q.push_front(t1);
                }
            }
        }
    }
    return 0;
}
